sql:
SELECT cd.country_id, ed.indicator_id, ed.last_value
FROM countries cd
JOIN economic_data ed ON cd.country_id = ed.country_id;

external_knowledge:
- 'large population' refers to a population above 50 million; 
- 'high GDP' refers to a GDP above $100 billion; 
- the 'last_value' in the economic_data table is assumed to represent the population in millions.

sql:
SELECT country_name, gdp
FROM countries
WHERE last_updated = (
  SELECT MAX(last_updated)
  FROM countries
);

